**src/App.jsx**
```jsx
import { useState } from 'react'
import { Brok } from '@brok/api'

const brok = new Brok({ apiKey: import.meta.env.BROK_API_KEY })

export default function App() {
  const [todos, setTodos] = useState([])
  const [input, setInput] = useState('')
  const [suggestion, setSuggestion] = useState(null)

  const addTodo = () => {
    if (!input.trim()) return
    setTodos([...todos, { id: Date.now(), text: input, done: false }])
    setInput('')
    setSuggestion(null)
  }

  const toggleTodo = (id) => {
    setTodos(todos.map(t => t.id === id ? { ...t, done: !t.done } : t))
  }

  const deleteTodo = (id) => {
    setTodos(todos.filter(t => t.id !== id))
  }

  const getSuggestion = async () => {
    if (!input.trim()) return
    const res = await brok.chat({ 
      message: `Suggest one short todo task complementary to "${input}". Reply with just the task.` 
    })
    setSuggestion(res.content)
  }

  const addSuggestion = () => {
    if (suggestion) {
      setTodos([...todos, { id: Date.now(), text: suggestion, done: false }])
      setSuggestion(null)
    }
  }

  return (
    <div className="container">
      <h1>✓ Tiny Todo</h1>

      <div className="input-row">
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && addTodo()}
          placeholder="What needs doing?"
        />
        <button onClick={addTodo}>Add</button>
        <button onClick={getSuggestion} className="ai-btn">✨ AI</button>
      </div>

      {suggestion && (
        <div className="suggestion">
          <span>{suggestion}</span>
          <button onClick={addSuggestion}>Add</button>
          <button onClick={() => setSuggestion(null)}>✕</button>
        </div>
      )}

      <ul>
        {todos.map(todo => (
          <li key={todo.id} className={todo.done ? 'done' : ''}>
            <input type="checkbox" checked={todo.done} onChange={() => toggleTodo(todo.id)} />
            <span>{todo.text}</span>
            <button onClick={() => deleteTodo(todo.id)}>✕</button>
          </li>
        ))}
      </ul>
    </div>
  )
}
```

